```class Solution:
    def addMinimum(self, word: str) -> int:
        stack = []
        count = 0
        for char in word:
            if char == 'a':
                stack.append(char)
            elif char == 'b':
                if stack and stack[-1] == 'a':
                    stack.pop()
                    stack.append('x') # 'x' represents 'ab'
                else:
                    stack.append(char)
            elif char == 'c':
                if stack and stack[-1] == 'x':
                    stack.pop()
                elif stack and stack[-1] == 'a':
                    count += 1
                else:
                    stack.append(char)
        return count + len(stack) // 2 + len(stack) % 2 * 2
